 1	import React, { FC } from 'react';
 2	import xbytes from 'xbytes';
 3	
 4	import {
 5	  AddBootableVolumeState,
 6	  SetBootableVolumeFieldType,
 7	} from '@kubevirt-utils/components/AddBootableVolumeModal/utils/constants';
 8	import { removeByteSuffix } from '@kubevirt-utils/components/CapacityInput/utils';
 9	import HelpTextIcon from '@kubevirt-utils/components/HelpTextIcon/HelpTextIcon';
10	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
11	import { hasSizeUnit } from '@kubevirt-utils/resources/vm/utils/disk/size';
12	import { Checkbox, PopoverPosition, Split, SplitItem } from '@patternfly/react-core';
13	
14	import DiskSourcePVCSelect from './DiskSourcePVCSelect';
15	
16	type PVCSourceProps = {
17	  bootableVolume: AddBootableVolumeState;
18	  setBootableVolumeField: SetBootableVolumeFieldType;
19	};
20	
21	const PVCSource: FC<PVCSourceProps> = ({ bootableVolume, setBootableVolumeField }) => {
22	  const { t } = useKubevirtTranslation();
23	  const { pvcName, pvcNamespace } = bootableVolume || {};
24	
25	  return (
26	    <>
27	      <DiskSourcePVCSelect
28	        setDiskSize={(newSize) =>
29	          setBootableVolumeField('size')(
30	            hasSizeUnit(newSize)
31	              ? removeByteSuffix(newSize)
32	              : removeByteSuffix(xbytes(Number(newSize), { iec: true, space: false })),
33	          )
34	        }
35	        pvcNameSelected={pvcName}
36	        pvcNamespaceSelected={pvcNamespace}
37	        selectPVCName={setBootableVolumeField('pvcName')}
38	        selectPVCNamespace={setBootableVolumeField('pvcNamespace')}
39	      />
40	      <Split hasGutter>
41	        <SplitItem>
42	          <Checkbox
43	            id="clone-pvc-checkbox"
44	            isChecked
45	            isDisabled
46	            label={t('Clone existing Volume')}
47	          />
48	        </SplitItem>
49	        <SplitItem>
50	          <HelpTextIcon
51	            bodyContent={t(
52	              'This will create a cloned copy of the Volume in the destination project.',
53	            )}
54	            position={PopoverPosition.right}
55	          />
56	        </SplitItem>
57	      </Split>
58	    </>
59	  );
60	};
61	
62	export default PVCSource;

